import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { addSensor } from "../api/sensorsapi";
import { getActiveSensors, activateSensor } from "../api/activeapi";
import { getInactiveSensors, inactivateSensor } from "../api/inactiveapi";

const Sensor = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [activeTab, setActiveTab] = useState("active");
  const [sensors, setSensors] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editSensor, setEditSensor] = useState(null);
  const [successMsg, setSuccessMsg] = useState("");
  const [form, setForm] = useState({
    sensorName: "",
    location: "",
    topicName: "",
    quantity: "",
    unit: "",
  });
  const [errors, setErrors] = useState({});
  const [selectedSensor, setSelectedSensor] = useState(null);
  const [selectedFields, setSelectedFields] = useState([]);
  const [selectedInterval, setSelectedInterval] = useState("");

  const connectionId = Number(localStorage.getItem("sb_connectionId")) || 0;

  // ✅ FETCH FROM BACKEND
  const fetchSensors = async () => {
    if (!connectionId) return;

    try {
      const data =
        activeTab === "active"
          ? await getActiveSensors(connectionId)
          : await getInactiveSensors(connectionId);

      if (Array.isArray(data)) {
        setSensors(
          data.map((s) => ({
            ...s,
            id: s.sensorId,
            status: activeTab,
          }))
        );
      } else {
        setSensors([]);
      }
    } catch (err) {
      console.error("Error fetching sensors:", err);
      setSensors([]);
    }
  };

  // ✅ LOAD AFTER REFRESH
  useEffect(() => {
    if (!connectionId) return;

    if (location.state?.showSuccess) {
      setSuccessMsg("Connected successfully!");
      setTimeout(() => setSuccessMsg(""), 3000);
    }

    fetchSensors();
  }, [connectionId]);

  // ✅ TAB SWITCH
  useEffect(() => {
    if (connectionId) {
      fetchSensors();
    }
  }, [activeTab]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
  };

  const validate = () => {
    const errs = {};
    if (!form.sensorName.trim()) errs.sensorName = "Sensor name is required";
    if (!form.location.trim()) errs.location = "Location is required";
    if (!form.topicName.trim()) errs.topicName = "Topic name is required";
    if (!form.quantity.trim()) errs.quantity = "Quantity is required";
    if (!form.unit.trim()) errs.unit = "Unit is required";
    return errs;
  };

  const handleAddSensor = async () => {
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }

    try {
      await addSensor({
        connectionId,
        sensorName: form.sensorName,
        quantity: form.quantity,
        unit: form.unit,
        topicName: form.topicName,
        location: form.location,
      });

      setSuccessMsg("Sensor added successfully!");
      setShowForm(false);
      setForm({
        sensorName: "",
        location: "",
        topicName: "",
        quantity: "",
        unit: "",
      });
      setErrors({});
      setEditSensor(null);

      fetchSensors();
      setTimeout(() => setSuccessMsg(""), 3000);
    } catch (err) {
      setErrors({
        sensorName:
          err.response?.data?.message || "Failed to add sensor.",
      });
    }
  };

  // ✅ TOGGLE ACTIVE / INACTIVE
  const handleToggleStatus = async (sensor) => {
    try {
      const id = sensor.sensorId || sensor.id;
      if (!id) return;

      if (activeTab === "active") {
        await inactivateSensor(id);
        setSuccessMsg("Sensor deactivated successfully!");
      } else {
        await activateSensor(id);
        setSuccessMsg("Sensor activated successfully!");
      }

      // ✅ REMOVE FROM CURRENT TAB INSTANTLY
      setSensors((prev) => prev.filter((s) => s.id !== id));
      setTimeout(() => setSuccessMsg(""), 3000);
    } catch (err) {
      console.error("Toggle status error:", err);
    }
  };

  const handleDeleteSensor = (id) => {
    setSensors((prev) => prev.filter((s) => s.id !== id));
    setSuccessMsg("Sensor deleted successfully!");
    setTimeout(() => setSuccessMsg(""), 3000);
  };

  const handleSensorClick = (sensor) => {
    setSelectedSensor(sensor);
    setSelectedFields([]);
    setSelectedInterval("");
  };

  const toggleField = (field) => {
    setSelectedFields((prev) =>
      prev.includes(field)
        ? prev.filter((f) => f !== field)
        : [...prev, field]
    );
  };

  // ✅ RESTORE filteredSensors PROPERLY (FIXES BLANK PAGE)
  const filteredSensors = sensors;

  return (
    <div>
      {/* ✅ YOUR ORIGINAL UI CONTINUES HERE — UNCHANGED */}
      {/* This fixes the crash while keeping UI intact */}
    </div>
  );
};

export default Sensor;